+/// Fold (X lshr N) + zext(icmp ne (X and (2^N - 1)), 0) --> (X + (2^N - 1)) lshr N
+/// This computes ceiling(X / 2^N).
+static Instruction *foldAddToLshr(BinaryOperator &Add) {
+  Value *Op0 = Add.getOperand(0);
+  Value *Op1 = Add.getOperand(1);
+
+  // Check for (X lshr N) + zext(icmp ne (X and Mask), 0) or swapped
+  auto *LShr = dyn_cast<BinaryOperator>(Op0);
+  auto *ZExt = dyn_cast<ZExtInst>(Op1);
+  if (!LShr || !ZExt || LShr->getOpcode() != Instruction::LShr) {
+    // Try swapped operands
+    LShr = dyn_cast<BinaryOperator>(Op1);
+    ZExt = dyn_cast<ZExtInst>(Op0);
+    if (!LShr || !ZExt || LShr->getOpcode() != Instruction::LShr)
+      return nullptr;
+  }
+
+  // Get X and shift amount from lshr
+  Value *X = LShr->getOperand(0);
+  auto *ShiftAmtC = dyn_cast<ConstantInt>(LShr->getOperand(1));
+  if (!ShiftAmtC)
+    return nullptr;
+  uint64_t ShiftAmt = ShiftAmtC->getZExtValue();
+
+  // Get icmp from zext
+  auto *ICmp = dyn_cast<ICmpInst>(ZExt->getOperand(0));
+  if (!ICmp || ICmp->getPredicate() != CmpInst::ICMP_NE)
+    return nullptr;
+
+  // Find the and operand and verify the other is zero
+  Value *AndOp = nullptr;
+  if (match(ICmp->getOperand(0), m_ZeroInt())) {
+    AndOp = ICmp->getOperand(1);
+  } else if (match(ICmp->getOperand(1), m_ZeroInt())) {
+    AndOp = ICmp->getOperand(0);
+  } else {
+    return nullptr;
+  }
+
+  // Check AndOp is (X and Mask)
+  auto *And = dyn_cast<BinaryOperator>(AndOp);
+  if (!And || And->getOpcode() != Instruction::And)
+    return nullptr;
+  
+  // Check and operand is X (handle commutativity)
+  Value *AndX = And->getOperand(0);
+  auto *MaskC = dyn_cast<ConstantInt>(And->getOperand(1));
+  if (!MaskC) {
+    AndX = And->getOperand(1);
+    MaskC = dyn_cast<ConstantInt>(And->getOperand(0));
+    if (!MaskC)
+      return nullptr;
+  }
+  
+  if (AndX != X)
+    return nullptr;
+
+  // Verify Mask = (2^ShiftAmt - 1)
+  APInt ExpectedMask = APInt::getLowBitsSet(MaskC->getBitWidth(), ShiftAmt);
+  if (MaskC->getValue() != ExpectedMask)
+    return nullptr;
+
+  // Compute (X + (2^ShiftAmt - 1)) lshr ShiftAmt
+  Value *AddC = ConstantInt::get(X->getType(), ExpectedMask);
+  Value *NewAdd = BinaryOperator::CreateAdd(X, AddC);
+  if (Add.hasNoUnsignedWrap())
+    cast<BinaryOperator>(NewAdd)->setHasNoUnsignedWrap(true);
+  if (Add.hasNoSignedWrap())
+    cast<BinaryOperator>(NewAdd)->setHasNoSignedWrap(true);
+  return BinaryOperator::CreateLShr(NewAdd, ConstantInt::get(Add.getType(), ShiftAmt));
+}
