static Instruction *foldAddToLshr(BinaryOperator &Add) {
  // Division must be by power-of-2. Recognize the pattern:
  // (X lshr N) + zext(icmp ne (X and (2^N - 1)), 0) --> (X + (2^N - 1)) lshr N
  // This computes ceiling(X / 2^N).
  Value *X;
  const APInt *ShiftAmt;
  if (!match(Add.getOperand(0), m_LShr(m_Value(X), m_APInt(ShiftAmt))))
    return nullptr;

  // Check the other operand is zext(icmp ne (X and Mask), 0)
  // where Mask = (2^ShiftAmt - 1)
  Value *AndX, *CmpX;
  const APInt *MaskC;
  if (!match(Add.getOperand(1),
             m_ZExt(m_OneUse(m_SpecificICmp(
                 ICmpInst::ICMP_NE, m_And(m_Value(AndX), m_APInt(MaskC)),
                 m_ZeroInt())))))
    return nullptr;

  // Verify AndX is the same as X from the lshr
  if (AndX != X)
    return nullptr;

  // Verify Mask = (2^ShiftAmt - 1)
  APInt ExpectedMask = APInt::getLowBitsSet(ShiftAmt->getBitWidth(), *ShiftAmt);
  if (*MaskC != ExpectedMask)
    return nullptr;

  // Compute (X + (2^ShiftAmt - 1)) lshr ShiftAmt
  Value *AddC = ConstantInt::get(X->getType(), ExpectedMask);
  Value *NewAdd = BinaryOperator::CreateAdd(X, AddC);
  if (Add.hasNoUnsignedWrap())
    cast<BinaryOperator>(NewAdd)->setHasNoUnsignedWrap(true);
  if (Add.hasNoSignedWrap())
    cast<BinaryOperator>(NewAdd)->setHasNoSignedWrap(true);
  return BinaryOperator::CreateLShr(NewAdd, ConstantInt::get(Add.getType(), *ShiftAmt));
}

